var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"20년 전, 직할 도시 <color=#ffd34c>프론트베이</color>","JPN":"20年前、直轄都市<color=#ffd34c>フロントベイ</color>","ENG":"20 years ago, Administration Direct Control City, <color=#ffd34c>Front Bay</color>","TWN":"20年前，直轄城市<color=#ffd34c>前灣</color>","DEU":"20 years ago, Administration Direct Control City, <color=#ffd34c>Front Bay</color>","FRA":"20 years ago, Administration Direct Control City, <color=#ffd34c>Front Bay</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"금방이라도 무너져 내릴 것 같은 표정이네, 에이버리?","JPN":"今にも泣き出しそうな顔よ、エイバリー。","ENG":"You look like you're about to fall apart, Avery.","TWN":"艾維利，你的表情看起來隨時都要崩潰了。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"그런 표정을 지으면 널 구해준 보니가 어떻게 눈을 감을 수 있겠니?","JPN":"そんな顔してたら、あなたを救ってくれたボニーが安らかに眠れないじゃない。","ENG":"If you make that face, how is Bonny supposed to rest easy?","TWN":"如果你露出那種表情，要救了你的寶妮怎麼瞑目呢？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"리드.","JPN":"リード。","ENG":"Read.","TWN":"里德。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"여기서 누구보다 내가 원망스러운 건 너일 텐데.","JPN":"この中で誰より私を恨んでいるのはお前だろうに。","ENG":"If anything, I'm the one you should resent most.","TWN":"在這裡，只有你比任何人都更有資格怨恨我。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"친한 동료를 나 때문에 잃은 것에 대해 화가 나지는 않나?","JPN":"大切な仲間が私のせいで犠牲になったのだ、恨めしくはないか？","ENG":"Aren't you angry that I caused the death of your close crewmate?","TWN":"我害你失去了親密的同伴，你不生氣嗎？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"<color=#ffd34c>선장은 배는 버려도 선원은 버리지 않는다.</color>","JPN":"<color=#ffd34c>船長は船は捨てても船員は捨てない。</color>","ENG":"<color=#ffd34c>The captain may abandon the ship, but doesn't abandon the crew.</color>","TWN":"<color=#ffd34c>船長可以捨棄船，但絕不會丟下船員。</color>"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"당신은 당신의 말을 지켰으니, 보니도 보니의 말을 지켰을 뿐이야.","JPN":"あなたが自分の言ったことを守ったから、ボニーも自分の言ったことを守ったまでよ。","ENG":"You kept your word, so Bonny simply kept hers.","TWN":"你遵守了自己的承諾，寶妮也只是遵守了她的約定而已。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"참 당돌한 부함장이었어.","JPN":"本当に大胆な副艦長だった。","ENG":"You were always such a bold first mate.","TWN":"你真是個魯莽的副船長啊。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"감히 선장 명령을 어기고 기함의 제어권까지 가져갔으니 말이야.","JPN":"船長命令なんて無視して、旗艦の制御権まで持って行ったからな。","ENG":"You even disobeyed the captain's orders and seized control of the Flagship.","TWN":"竟敢違抗船長命令，還搶走旗艦的控制權。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"가려는 거야? 출항 준비를 하면 되는 걸까?","JPN":"行くの？　出航の準備をすればいいのかしら。","ENG":"You're leaving? Should I start preparing for departure?","TWN":"你要走了？那我是不是該準備起航了？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"새 배라면 어떻게든 구해볼 테니까…….","JPN":"新しい船なら、どうにか探してみる手はあるから……","ENG":"If it's a new ship you need, I'll find one somehow–","TWN":"我會想辦法弄來新船……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"난 관리국의 제안을 받아들일 생각이야.","JPN":"私は管理局の提案に乗るつもりだ。","ENG":"I'm going to accept the Administration's offer.","TWN":"我打算接受管理局的提案。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"……그렇구나.","JPN":"……そう。","ENG":"...I see.","TWN":"……這樣啊。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"관리국의 기함 <color=#ffd34c>인빈서블</color> 덕분에 그 괴물을 쓰러뜨리고 나서 깨달았어.","JPN":"管理局の旗艦<color=#ffd34c>インビンシブル</color>のおかげであの化け物を倒してから、悟ったんだ。","ENG":"After bringing down that monster thanks to the Administration's Flagship, <color=#ffd34c>Invincible</color>, I realized something.","TWN":"在靠管理局旗艦<color=#ffd34c>無敵號</color>擊倒那隻怪物後，我終於懂了。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"이제 우리 힘만으로는 고향을 지킬 수 없다는 것을.","JPN":"これ以上、私たちの力だけでは故郷を守れないということを。","ENG":"We can't protect our home on our own anymore.","TWN":"我們已經無法只靠自己的力量守護家鄉。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"보니도 그걸 알아서 그런 선택을 내린 거겠지.","JPN":"ボニーもそれが分かったからあんな選択をしたのだろう。","ENG":"Bonny must have known that too. That's why she chose what she did.","TWN":"寶妮也是明白這點，才做出那樣的選擇吧。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"다른 선원들한테는 얘기해 뒀어.","JPN":"他の船員たちには話しておいた。","ENG":"I've already spoken with the others.","TWN":"我已經跟其他船員說了。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"어떻게 받아들일지는 모르겠지만, 각자 생각이 있을 거다.","JPN":"どう受けとめるかはわからないが、みんな思うところがあるはず。","ENG":"I don't know how they'll take it, but everyone has their own thoughts.","TWN":"他們會怎麼想我不清楚，但每個人都有自己的選擇。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"리드. 넌 이제 어쩔 생각이지?","JPN":"リード、お前はこれからどうする？","ENG":"Read. What do you intend to do now?","TWN":"里德，你接下來打算怎麼辦？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"글쎄. 그 해군 아저씨나 다시 괴롭히러 가는 것도 괜찮겠는데?","JPN":"そうね。またあの海軍のおじさんを悩ませに戻るのも悪くないわね。","ENG":"Well, maybe I'll go bother that navy fellow again.","TWN":"嗯，再去找那個海軍大叔的麻煩也不錯？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"훗, 그 샌님이 꽤 재밌어 보인 모양이군.","JPN":"ふっ、あの堅物、相当からかい甲斐があったようだな。","ENG":"Haha. Seems that stuffy fellow piqued your interest.","TWN":"呵，看來你覺得那個書呆子很有趣嘛。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그래… 그게 너 다운 행동이지.","JPN":"そうだな……そうしている方がお前らしい。","ENG":"Yeah... that's just like you.","TWN":"的確……那很像你會做的事。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"좋아, 선장 명령이다.","JPN":"よし、船長命令だ。","ENG":"All right. Captain's orders.","TWN":"好，這是船長的命令。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"에이버리 해적단은 오늘로 해산.","JPN":"エイバリー海賊団は本日にて解散。","ENG":"The Avery Pirates are disbanded as of today.","TWN":"艾維利海盜團自今日起解散。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"사유는 선장 및 해적단 전원 실종이다.","JPN":"船長および海賊団全員の失踪が、その理由だ。","ENG":"Reason being the captain and all crew are missing.","TWN":"理由是船長與海盜團全員失踪。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"하지만… 그렇게 되면 <color=#ffd34c>그 아이</color>는 어떻게 할 생각이야?","JPN":"でも……そうなったら<color=#ffd34c>あの子</color>はどうするつもり？","ENG":"But... what about <color=#ffd34c>the girl</color>?","TWN":"但是……這樣的話你打算怎麼處理<color=#ffd34c>那孩子</color>？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"우리는 죽은 사람들이야, 리드.","JPN":"私たちは死んだんだ、リード。","ENG":"We're basically dead people, Read.","TWN":"我們已經是死人了，里德。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_AVERY","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"사람들이 과거의 망령에 사로잡히지 않도록, 나는 얼굴을 가리고, 목소리를 변조하여 살아갈 생각이야.","JPN":"人々が過去の亡霊に囚われないよう、私は顔を隠し、声を変えて今後生きていくつもりさ。","ENG":"I'm gonna hide my face and change my voice, so people don't cling to the ghosts of the past.","TWN":"為了不讓大家被過去的亡靈束縛，我會遮住自己的臉、改變聲音活下去。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_AVERY","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};